import React from 'react'
import { Col, Row } from 'reactstrap';
import KarimField from '../../Components/Karimalden/KarimField';
import { FakeSelectData } from '../../Layout/app/Const';

function FormExample() {

  return (
    <Row xs={1} sm={1} md={1} lg={2} xl={2}>
    <Col>
    <KarimField name="name" type="text"la  placeholder='placeholder' />
    <KarimField name="number" type="number" la placeholder='placeholder' />
    <KarimField name="select" type="select"la  option={FakeSelectData} isMulti={true} placeholder='placeholder'  />
    <KarimField name="Multiselect" type="select"la  option={FakeSelectData} Disabled={true} placeholder='placeholder'/>


    </Col>
    <Col>
   <KarimField name="date" type="date" la placeholder='placeholder' />
   <KarimField name="time" type="text"la  placeholder='placeholder' />
   <KarimField name="CheckBox" type="checkbox" la placeholder='placeholder' />

    </Col>
  </Row>
  )
}

export default FormExample
